# ── User Store Persistence ────────────────────────────────────
def load_user_store():
    if not APP_DATA_PATH.exists():
        return {"saved_portfolios": {}, "watchlists": {}, "alerts": []}
    try:
        return json.loads(APP_DATA_PATH.read_text(encoding="utf-8"))
    except Exception:
        return {"saved_portfolios": {}, "watchlists": {}, "alerts": []}


def save_user_store(store):
    APP_DATA_PATH.write_text(json.dumps(store, indent=2), encoding="utf-8")


def sync_user_store_to_session():
    store = load_user_store()
    st.session_state.saved_portfolios = store.get("saved_portfolios", {})
    st.session_state.watchlists = store.get("watchlists", {})
    st.session_state.alerts = store.get("alerts", [])


def persist_session_user_store():
    save_user_store({
        "saved_portfolios": st.session_state.get("saved_portfolios", {}),
        "watchlists": st.session_state.get("watchlists", {}),
        "alerts": st.session_state.get("alerts", []),
    })



