def load_portfolio_payload(payload):
    st.session_state.tickers = list(payload.get("tickers", []))
    st.session_state.start_date = payload.get("start_date", st.session_state.start_date)
    st.session_state.end_date = payload.get("end_date", st.session_state.end_date)
    st.session_state.min_w = float(payload.get("min_w", st.session_state.min_w))
    st.session_state.max_w = float(payload.get("max_w", st.session_state.max_w))
    st.session_state.target_return = float(payload.get("target_return", st.session_state.target_return))
    st.session_state.shrinkage_alpha = float(payload.get("shrinkage_alpha", st.session_state.shrinkage_alpha))
    st.session_state.momentum_enabled = bool(payload.get("momentum_enabled", st.session_state.momentum_enabled))
    st.session_state.momentum_beta = float(payload.get("momentum_beta", st.session_state.momentum_beta))
    st.session_state.momentum_lookback = int(payload.get("momentum_lookback", st.session_state.momentum_lookback))
    st.session_state.data_loaded = False
    st.session_state.portfolios_computed = False
    st.session_state.frontier_computed = False
    st.session_state.weights_utility = None
    st.session_state.weights_tan = None
    st.session_state.weights_min = None
    st.session_state.momentum_scores = None
    st.session_state.momentum_signals = None
    st.session_state.momentum_final_er = None
    st.session_state.momentum_meta = None


