# ── Universe Bridge ───────────────────────────────────────────
def load_universe_bridge():
    if not UNIVERSE_BRIDGE_PATH.exists():
        return None
    try:
        return json.loads(UNIVERSE_BRIDGE_PATH.read_text(encoding="utf-8"))
    except Exception:
        return None


def save_universe_bridge(payload):
    UNIVERSE_BRIDGE_PATH.write_text(json.dumps(payload, indent=2), encoding="utf-8")


def clear_universe_bridge():
    try:
        if UNIVERSE_BRIDGE_PATH.exists():
            UNIVERSE_BRIDGE_PATH.unlink()
    except Exception:
        pass


def push_bridge_symbols(symbols, mode, source):
    clean = normalize_symbol_list(",".join(symbols))
    if not clean:
        return False
    save_universe_bridge({
        "symbols": clean,
        "mode": mode,
        "source": source,
        "created_at": pd.Timestamp.now().strftime("%Y-%m-%d %H:%M:%S"),
    })
    return True


def consume_bridge_symbols():
    payload = load_universe_bridge()
    if not payload:
        return
    symbols = normalize_symbol_list(",".join(payload.get("symbols", [])))
    if not symbols:
        clear_universe_bridge()
        return
    mode = payload.get("mode", "replace")
    source = payload.get("source", "helper desk")
    apply_ticker_set(symbols, mode=mode)
    st.session_state.flash_notice = (
        "success",
        f"{'Replaced' if mode == 'replace' else 'Appended'} basket from {source}: {len(symbols)} symbols imported."
    )
    clear_universe_bridge()



# ── Symbol Utilities ──────────────────────────────────────────
def normalize_symbol_list(raw_text):
    if not raw_text:
        return []
    cleaned = raw_text.replace("\n", ",").replace(";", ",")
    symbols = []
    seen = set()
    for part in cleaned.split(","):
        symbol = part.strip().upper()
        if not symbol or symbol in seen:
            continue
        symbols.append(symbol)
        seen.add(symbol)
    return symbols


def parse_uploaded_symbols(uploaded_file):
    if uploaded_file is None:
        return []
    try:
        name = uploaded_file.name.lower()
        if name.endswith(".csv"):
            df = pd.read_csv(uploaded_file)
        elif name.endswith(".xlsx") or name.endswith(".xls"):
            df = pd.read_excel(uploaded_file)
        else:
            text = uploaded_file.getvalue().decode("utf-8", errors="ignore")
            return normalize_symbol_list(text)
        if df.empty:
            return []
        lowered = {str(c).strip().lower(): c for c in df.columns}
        for candidate in ["symbol", "ticker", "tickers", "symbols", "instrument"]:
            if candidate in lowered:
                col = lowered[candidate]
                return normalize_symbol_list(",".join(df[col].dropna().astype(str).tolist()))
        first_col = df.columns[0]
        return normalize_symbol_list(",".join(df[first_col].dropna().astype(str).tolist()))
    except Exception:
        return []


def apply_ticker_set(symbols, mode="replace"):
    resolved = []
    seen = set()
    base = st.session_state.tickers if mode == "append" else []
    for ticker in base:
        if ticker not in seen:
            resolved.append(ticker)
            seen.add(ticker)
    for symbol in symbols:
        final_symbol = symbol
        if "." not in symbol and "=" not in symbol and "^" not in symbol and "-" not in symbol:
            try:
                final_symbol = get_best_ticker(
                    symbol,
                    st.session_state.start_date,
                    st.session_state.end_date,
                )
            except Exception:
                final_symbol = symbol
        if final_symbol not in seen:
            resolved.append(final_symbol)
            seen.add(final_symbol)
    st.session_state.tickers = resolved
    reset_portfolio_outputs()


# ── Auto Max Weight ───────────────────────────────────────────
def compute_max_w(n: int) -> float:
    if n <= 3:   return 0.40
    if n <= 10:  return 0.30
    if n <= 20:  return 0.20
    if n <= 40:  return 0.15
    return 0.10



